      "content": "// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const taskService = require('../tasks/service');
const { sendError } = require('../../lib/errors');
const { validateTaskStatus } = require('../../lib/validation');

router.get('/', async (req, res) => {
  try {
    const statusFilter = req.query.status;
    const tasks = await taskService.getTasks(statusFilter);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;

  if (!validateTaskStatus(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }

  try {
    const updatedTask = await taskService.updateTask(taskId, status);
    if (updatedTask) {
      res.json({ task: updatedTask });
    } else {
      sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
