      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const { validateTaskStatus } = require('../../lib/validation');

let tasksStore = [];

module.exports = {
  getTasks(statusFilter) {
    if (statusFilter) {
      return tasksStore.filter(task => task.status === statusFilter);
    }
    return tasksStore.slice();
  },

  updateTask(taskId, newStatus) {
    const taskIndex = tasksStore.findIndex(task => task.id === taskId);
    if (taskIndex !== -1 && validateTaskStatus(newStatus)) {
      tasksStore[taskIndex].status = newStatus;
      return tasksStore[taskIndex];
    }
    return null;
  },

  createTask(projectId, taskData) {
    const taskId = randomUUID();
    const task = { id: taskId, projectId, ...taskData, status: 'todo' };
    tasksStore.push(task);
    return task;
  }
};"
